#!/usr/bin/env python3\n\"\"\"\nConfiguration Settings for Portable Solar Power Generator\nMS Engineering College Final Year Project\n\"\"\"\n\nimport json\nimport os\nfrom typing import Dict, Any\n\nclass SystemConfig:\n    \"\"\"System configuration management\"\"\"\n    \n    def __init__(self, config_file: str = \"config/system_config.json\"):\n        self.config_file = config_file\n        self.config = self._load_default_config()\n        self.load_config()\n    \n    def _load_default_config(self) -> Dict[str, Any]:\n        \"\"\"Load default configuration settings\"\"\"\n        return {\n            \"system\": {\n                \"name\": \"Portable Solar Power Generator\",\n                \"version\": \"1.0.0\",\n                \"college\": \"MS Engineering College\",\n                \"university\": \"Visvesvaraya Technological University\"\n            },\n            \"team\": {\n                \"leader\": \"Ritik Pandey\",\n                \"developer\": \"Rohit Ranjan\", \n                \"documentation\": \"Nikki Kumari Yadav\",\n                \"research\": \"Om Singh\"\n            },\n            \"battery\": {\n                \"capacity_ah\": 20,\n                \"voltage_nominal\": 12.0,\n                \"voltage_min\": 10.5,\n                \"voltage_max\": 14.4,\n                \"low_battery_threshold\": 15.0,\n                \"critical_battery_threshold\": 5.0\n            },\n            \"solar_panel\": {\n                \"power_rating_w\": 50,\n                \"voltage_nominal\": 12.0,\n                \"voltage_max\": 20.0,\n                \"efficiency\": 0.85\n            },\n            \"devices\": {\n                \"light\": {\n                    \"power_w\": 5,\n                    \"voltage\": 12,\n                    \"consumption_rate\": 0.5\n                },\n                \"fan\": {\n                    \"power_w\": 10,\n                    \"voltage\": 12,\n                    \"consumption_rate\": 1.0\n                },\n                \"mobile_charger\": {\n                    \"power_w\": 10,\n                    \"voltage\": 5,\n                    \"consumption_rate\": 0.8\n                }\n            },\n            \"safety\": {\n                \"max_temperature\": 60,\n                \"max_discharge_current\": 15,\n                \"emergency_shutdown_enabled\": True,\n                \"auto_recovery_enabled\": True\n            },\n            \"monitoring\": {\n                \"log_interval_seconds\": 60,\n                \"data_retention_days\": 30,\n                \"enable_remote_monitoring\": True\n            },\n            \"interface\": {\n                \"mobile_app_enabled\": True,\n                \"remote_control_enabled\": True,\n                \"web_interface_enabled\": False,\n                \"api_enabled\": False\n            }\n        }\n    \n    def load_config(self) -> None:\n        \"\"\"Load configuration from file\"\"\"\n        try:\n            if os.path.exists(self.config_file):\n                with open(self.config_file, 'r') as f:\n                    file_config = json.load(f)\n                    self._merge_config(file_config)\n        except Exception as e:\n            print(f\"Warning: Could not load config file: {e}\")\n            print(\"Using default configuration\")\n    \n    def save_config(self) -> bool:\n        \"\"\"Save current configuration to file\"\"\"\n        try:\n            os.makedirs(os.path.dirname(self.config_file), exist_ok=True)\n            with open(self.config_file, 'w') as f:\n                json.dump(self.config, f, indent=4)\n            return True\n        except Exception as e:\n            print(f\"Error saving config: {e}\")\n            return False\n    \n    def _merge_config(self, new_config: Dict[str, Any]) -> None:\n        \"\"\"Merge new configuration with existing\"\"\"\n        def merge_dict(base: dict, update: dict) -> dict:\n            for key, value in update.items():\n                if key in base and isinstance(base[key], dict) and isinstance(value, dict):\n                    merge_dict(base[key], value)\n                else:\n                    base[key] = value\n            return base\n        \n        merge_dict(self.config, new_config)\n    \n    def get(self, key_path: str, default=None):\n        \"\"\"Get configuration value using dot notation\"\"\"\n        keys = key_path.split('.')\n        value = self.config\n        \n        try:\n            for key in keys:\n                value = value[key]\n            return value\n        except (KeyError, TypeError):\n            return default\n    \n    def set(self, key_path: str, value: Any) -> None:\n        \"\"\"Set configuration value using dot notation\"\"\"\n        keys = key_path.split('.')\n        config = self.config\n        \n        for key in keys[:-1]:\n            if key not in config:\n                config[key] = {}\n            config = config[key]\n        \n        config[keys[-1]] = value\n    \n    def get_team_info(self) -> Dict[str, str]:\n        \"\"\"Get team member information\"\"\"\n        return self.config.get('team', {})\n    \n    def get_system_info(self) -> Dict[str, str]:\n        \"\"\"Get system information\"\"\"\n        return self.config.get('system', {})\n    \n    def get_battery_config(self) -> Dict[str, float]:\n        \"\"\"Get battery configuration\"\"\"\n        return self.config.get('battery', {})\n    \n    def get_device_config(self, device: str) -> Dict[str, Any]:\n        \"\"\"Get device-specific configuration\"\"\"\n        return self.config.get('devices', {}).get(device, {})\n    \n    def is_feature_enabled(self, feature: str) -> bool:\n        \"\"\"Check if a feature is enabled\"\"\"\n        return self.config.get('interface', {}).get(f'{feature}_enabled', False)\n\n# Global configuration instance\nconfig = SystemConfig()\n\n# Save default config on first run\nif not os.path.exists(config.config_file):\n    config.save_config()\n    print(f\"Default configuration saved to {config.config_file}\")\n\nif __name__ == \"__main__\":\n    print(\"System Configuration:\")\n    print(\"=\" * 40)\n    \n    system_info = config.get_system_info()\n    print(f\"Project: {system_info.get('name')}\")\n    print(f\"Version: {system_info.get('version')}\")\n    print(f\"College: {system_info.get('college')}\")\n    \n    print(\"\\nTeam Members:\")\n    team_info = config.get_team_info()\n    for role, name in team_info.items():\n        print(f\"• {role.title()}: {name}\")\n    \n    print(\"\\nBattery Configuration:\")\n    battery_config = config.get_battery_config()\n    print(f\"• Capacity: {battery_config.get('capacity_ah')}Ah\")\n    print(f\"• Voltage: {battery_config.get('voltage_nominal')}V\")\n    print(f\"• Low threshold: {battery_config.get('low_battery_threshold')}%\")